def process_graph(graph_data):
    graph_copy = graph_data.copy()

    # Find node ID with the name 'ju1.a4.m4.s3c8.p1'
    node_to_remove_id = None
    for node_id, data in graph_copy.nodes(data=True):
        if data.get('name') == 'ju1.a4.m4.s3c8.p1':
            node_to_remove_id = node_id
            break
    if node_to_remove_id is not None:
        graph_copy.remove_node(node_to_remove_id)

    # Find node ID for the container 'ju1.a4.m4.s3c8' of type EK_PACKET_SWITCH
    container_id = None
    for node_id, data in graph_copy.nodes(data=True):
        if data.get('name') == 'ju1.a4.m4.s3c8' and 'EK_PACKET_SWITCH' in data.get('type', []):
            container_id = node_id
            break

    port_count = 0
    if container_id is not None:
        # Traverse out edges from container_id with type 'RK_CONTAINS'
        for _, child_id, edge_data in graph_copy.out_edges(container_id, data=True):
            if edge_data.get('type') == 'RK_CONTAINS':
                child_type = graph_copy.nodes[child_id].get('type', [])
                if 'EK_PORT' in child_type:
                    port_count += 1

    # Prepare the return object
    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)
    return_object = {
        'type': 'text',
        'data': str(port_count),
        'updated_graph': graph_json
    }
    return return_object
